DROP TABLE IF EXISTS `contas`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contas` (
  `cod_conta` varchar(5) NOT NULL,
  `cod_cliente` varchar(5) NOT NULL,
  `cod_agencia` varchar(5) NOT NULL,
  `cod_tipo_conta` varchar(5) NOT NULL,
  `cod_status` varchar(5) NOT NULL,
  `numero_conta` varchar(20) NOT NULL,
  `saldo_inicial` decimal(15,2) DEFAULT '0.00',
  `data_abertura` date NOT NULL,
  `cod_gerente` varchar(5) DEFAULT NULL,
  PRIMARY KEY (`cod_conta`),
  UNIQUE KEY `uk_contas_numero_conta` (`numero_conta`),
  KEY `ix_contas_cod_cliente` (`cod_cliente`),
  KEY `ix_contas_cod_agencia` (`cod_agencia`),
  KEY `ix_contas_cod_tipo_conta` (`cod_tipo_conta`),
  KEY `ix_contas_cod_status` (`cod_status`),
  KEY `ix_contas_gerente_agencia` (`cod_gerente`,`cod_agencia`),
  CONSTRAINT `fk_contas_agencias` FOREIGN KEY (`cod_agencia`) REFERENCES `agencias` (`cod_agencia`),
  CONSTRAINT `fk_contas_clientes` FOREIGN KEY (`cod_cliente`) REFERENCES `clientes` (`cod_cliente`),
  CONSTRAINT `fk_contas_gerente_agencia` FOREIGN KEY (`cod_gerente`, `cod_agencia`) REFERENCES `gerentes` (`cod_gerente`, `cod_agencia`),
  CONSTRAINT `fk_contas_status_conta` FOREIGN KEY (`cod_status`) REFERENCES `status_conta` (`cod_status`),
  CONSTRAINT `fk_contas_tipos_conta` FOREIGN KEY (`cod_tipo_conta`) REFERENCES `tipos_conta` (`cod_tipo_conta`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

